def __post(self, data: str) -> str:
    headers = {'Content-Type': 'application/xml'} 
    r = requests.post(
        f'{self.BASE_URL}:{self.PORT}/Exec',
        data=data,
        verify=False,
        headers=headers,
        cert=(self.CERT_FILE, self.KEY_FILE)
    )
    return r.text

